import { getSignaturePublicKey, } from '@sonolus/core';
import { webcrypto } from 'node:crypto';
import { authenticateServerRequestSchema } from '../schemas/server/authenticate.js';
import { parse } from '../utils/json.js';
import { handleError } from './error.js';
export const createServerAuthenticateRouteHandler = (sonolus) => async ({ req, res, localize, ctx }) => {
    if (!sonolus.authenticateHandler) {
        res.status(404).end();
        return;
    }
    const body = req.body;
    if (!(body instanceof Buffer)) {
        res.status(400).end();
        return;
    }
    const request = parse(body, authenticateServerRequestSchema);
    if (!request) {
        res.status(400).end();
        return;
    }
    if (request.address !== sonolus.address) {
        res.status(400).end();
        return;
    }
    if (request.time + 60 * 1000 < Date.now()) {
        res.status(400).end();
        return;
    }
    const signature = req.headers['sonolus-signature'];
    if (typeof signature !== 'string') {
        res.status(400).end();
        return;
    }
    const signaturePublicKey = await getSignaturePublicKey();
    const result = await webcrypto.subtle.verify({ name: 'ECDSA', hash: 'SHA-256' }, signaturePublicKey, Buffer.from(signature, 'base64'), body);
    if (!result) {
        res.status(400).end();
        return;
    }
    const response = await sonolus.authenticateHandler({
        ...ctx,
        userProfile: request.userProfile,
    });
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
